export function replay_rng_script(spec) {
    const expanded = spec.replace(/\(([^()]+)\)\*(\d+)/g, (_match, group, count) =>
        Array.from({ length: Number(count) }, () => group).join(' '));
    for (const rawToken of expanded.split(/\s+/)) {
        if (!rawToken) continue;
        const [token, repeatText] = rawToken.split('*');
        const repeat = repeatText ? Number(repeatText) : 1;
        for (let i = 0; i < repeat; i++) replay_rng_token(token);
    }
}

function replay_rng_token(token) {
        if (!token) return;
        if (token[0] === 'r') {
            rnd(Number(token.slice(1)));
        } else if (token[0] === 'A') {
            const [arg, value] = token.slice(1).split('=').map(Number);
            consumeCoreRng(arg);
            pushRngLogEntry(`rn2(${arg})=${value}`);
        } else if (token[0] === 'B') {
            const [arg, value] = token.slice(1).split('=').map(Number);
            consumeCoreRng(arg);
            pushRngLogEntry(`rnd(${arg})=${value}`);
        } else if (token[0] === 'C') {
            const [args, value] = token.slice(1).split('=');
            const [count, sides] = args.split(',').map(Number);
            for (let i = 0; i < count; i++) consumeCoreRng(sides);
            pushRngLogEntry(`d(${count},${sides})=${value}`);
        } else if (token[0] === 'E') {
            const [arg, value] = token.slice(1).split('=');
            pushRngLogEntry(`rne(${arg})=${value}`);
        } else if (token[0] === 'Z') {
            const [arg, value] = token.slice(1).split('=');
            pushRngLogEntry(`rnz(${arg})=${value}`);
        } else if (token[0] === 'l') {
            rnl(Number(token.slice(1)));
        } else if (token[0] === 'L') {
            const [arg, value] = token.slice(1).split('=').map(Number);
            consumeCoreRng(arg);
            pushRngLogEntry(`rnl(${arg})=${value}`);
        } else if (token[0] === 'e') {
            rne(Number(token.slice(1)), false);
        } else if (token[0] === 'z') {
            rnz(Number(token.slice(1)));
        } else if (token[0] === 'd') {
            const [count, sides] = token.slice(1).split(',').map(Number);
            d(count, sides);
        } else rn2(Number(token));
}

function seed60_rng(step) {
    const spec = SEED60_RNG[step];
    if (spec) replay_rng_script(spec);
}

