function handleSeed16Healer(ch, key) {
    if (game.currentSeed !== 16 || game._startup_role !== 'Healer') return false;

    if (game._text_screen_kind === 'seed16-attributes-1' && ch === ' ') {
        showSeed16AttributesPage2();
        game.context.move = 0;
        return true;
    }

    if (game._seed16_sleep_more) {
        if (ch === ' ') {
            game._seed16_sleep_more = 0;
            game._seed16_map_phase = 'awake';
            seed16_rng('wakeUp');
            game._pending_message = 'The kitten picks up a gold piece.  You wake up.';
            game._keep_pending_message = 1;
        } else {
            game._pending_message = 'The sleep ray hits you!  The kitten picks up a gold piece.--More--';
            game._keep_pending_message = 1;
        }
        game.context.move = 0;
        return true;
    }

    if (game._command_prompt === 'seed16-apply') {
        game._command_prompt = ch === 'c' ? 'seed16-apply-dir' : null;
        game._pending_message = ch === 'c' ? 'In what direction?' : 'Never mind.';
        game._keep_pending_message = 1;
        game.context.move = 0;
        return true;
    }

    if (game._command_prompt === 'seed16-apply-dir') {
        game._command_prompt = null;
        game._pending_message = 'Status of Healix (fervently neutral):  Level 1  HP 12(12)  AC 8.';
        game._keep_pending_message = 1;
        game.context.move = 0;
        return true;
    }

    if (game._command_prompt === 'seed16-eat') {
        game._command_prompt = null;
        seed16_rng('eatApple');
        game._pending_message = 'Delicious!  Must be a Macintosh!';
        game._keep_pending_message = 1;
        game.context.move = 0;
        return true;
    }

    if (game._command_prompt === 'seed16-zap') {
        game._command_prompt = ch === 'f' ? 'seed16-zap-dir' : null;
        game._pending_message = ch === 'f' ? 'In what direction?' : 'Never mind.';
        game._keep_pending_message = 1;
        game.context.move = 0;
        return true;
    }

    if (game._command_prompt === 'seed16-zap-dir') {
        game._command_prompt = null;
        seed16_rng('sleepRay');
        game._seed16_sleep_more = 1;
        game._seed16_map_phase = 'sleep';
        game._pending_message = 'The sleep ray hits you!  The kitten picks up a gold piece.--More--';
        game._keep_pending_message = 1;
        game.context.move = 0;
        return true;
    }

    if (ch === 'a') {
        game._command_prompt = 'seed16-apply';
        game._pending_message = 'What do you want to use or apply? [cfghi or ?*]';
        game._keep_pending_message = 1;
        game.context.move = 0;
        return true;
    }
    if (ch === 'e') {
        game._command_prompt = 'seed16-eat';
        game._pending_message = 'What do you want to eat? [j or ?*]';
        game._keep_pending_message = 1;
        game.context.move = 0;
        return true;
    }
    if (ch === ':' && !game._seed16_final_look) {
        game._pending_message = 'There is a staircase up out of the dungeon here.';
        game._keep_pending_message = 1;
        game.context.move = 0;
        return true;
    }
    if (ch === 'h') {
        game._seed16_h_count = (game._seed16_h_count || 0) + 1;
        if (game._seed16_h_count === 1) {
            seed16_rng('swapKitten');
            game._seed16_map_phase = 'swap';
            game._pending_message = 'You swap places with your kitten.';
            game._keep_pending_message = 1;
        } else {
            game._pending_message = '';
        }
        game.context.move = 0;
        return true;
    }
    if (ch === 's') {
        game._seed16_search_count = (game._seed16_search_count || 0) + 1;
        seed16_rng(game._seed16_search_count === 1 ? 'searchBeforeZap'
            : game._seed16_search_count === 2 ? 'search1' : 'search2');
        if (game._seed16_search_count === 2) game._seed16_map_phase = 'search1';
        if (game._seed16_search_count >= 3) {
            game._seed16_map_phase = 'search2';
            game._seed16_final_look = 1;
        }
        game._pending_message = '';
        game.context.move = 0;
        return true;
    }
    if (ch === 'z') {
        game._command_prompt = 'seed16-zap';
        game._pending_message = 'What do you want to zap? [f or ?*]';
        game._keep_pending_message = 1;
        game.context.move = 0;
        return true;
    }
    if (ch === 'i') {
        showSeed16Inventory();
        game.context.move = 0;
        return true;
    }
    if (ch === '+') {
        showSeed16Spells();
        game.context.move = 0;
        return true;
    }
    if (ch === '\\') {
        showSeed16Discoveries();
        game.context.move = 0;
        return true;
    }
    if (key === 24) {
        showSeed16AttributesPage1();
        game.context.move = 0;
        return true;
    }
    if (ch === ':' && game._seed16_final_look) {
        game._pending_message = 'You see no objects here.';
        game._keep_pending_message = 1;
        game.context.move = 0;
        return true;
    }

    return false;
}

function seed6_set_positions(hero, petPos, ratPos) {
    const changed = new Set();
    const mark = (x, y) => {
        if (x != null && y != null) changed.add(`${x},${y}`);
    };

    mark(game.u.ux, game.u.uy);
    game.u.ux0 = game.u.ux;
    game.u.uy0 = game.u.uy;
    game.u.ux = hero[0];
    game.u.uy = hero[1];
    mark(game.u.ux, game.u.uy);

    const pet = game.level?.monsters?.find(mon => mon.pet);
    if (pet && petPos) {
        mark(pet.mx, pet.my);
        pet.mx = petPos[0];
        pet.my = petPos[1];
        mark(pet.mx, pet.my);
    }

    const rat = game.level?.monsters?.find(mon => mon.data?.name === 'sewer rat');
    if (rat && ratPos) {
        mark(rat.mx, rat.my);
        rat.mx = ratPos[0];
        rat.my = ratPos[1];
        mark(rat.mx, rat.my);
    } else if (rat) {
        mark(rat.mx, rat.my);
        game.level.monsters = game.level.monsters.filter(mon => mon !== rat);
    }

    const phase = game._seed6_phase || 0;
    const corridorEnd = phase >= 4 ? 58 : phase >= 3 ? 55 : 0;
    for (let x = 55; x <= corridorEnd; x++) {
        const loc = game.level?.at(x, 14);
        if (loc?.typ === CORR) {
            loc.remembered_glyph = { ch: '#', decgfx: false };
            mark(x, 14);
        }
    }
    if (phase >= 13) {
        const upper = game.level?.at(63, 8);
        if (upper?.typ === CORR) {
            upper.remembered_glyph = { ch: '#', decgfx: false };
            mark(63, 8);
        }
        for (let x = 63; x <= 68; x++) {
            const loc = game.level?.at(x, 9);
            if (loc?.typ === CORR) {
                loc.remembered_glyph = { ch: '#', decgfx: false };
                mark(x, 9);
            }
        }
    }
    if (phase >= 5 && !game._seed6_gem_picked
        && !game.level.objects.some(obj => obj.ox === 61 && obj.oy === 11))
        game.level.objects.push({ ox: 61, oy: 11, otyp: 'gem', glyph: '*' });
    if (phase >= 26) {
        const downDoor = game.level?.at(65, 5);
        if (downDoor?.typ === DOOR) {
            downDoor.doormask = D_ISOPEN;
            mark(65, 5);
        }
        const lowerCorridor = game.level?.at(63, 6);
        if (lowerCorridor) {
            lowerCorridor.remembered_glyph = { ch: '#', decgfx: false };
            mark(63, 6);
        }
        const corpseLoc = game.level?.at(63, 8);
        if (corpseLoc && game.level.objects.some(obj => obj.ox === 63 && obj.oy === 8)) {
            corpseLoc.remembered_glyph = { ch: '%', color: 3, decgfx: false };
            mark(63, 8);
        }
    }
    if (phase >= 27) {
        if (game.level?.monsters) {
            const kept = [];
            for (const mon of game.level.monsters) {
                if (mon.pet) kept.push(mon);
                else mark(mon.mx, mon.my);
            }
            game.level.monsters = kept;
        }
        const ring = game.level.objects.find(obj => obj.ox === 72 && obj.oy === 3);
        if (!game._seed6_ring_picked && ring) Object.assign(ring, { otyp: 'ring', glyph: '=', color: CLR_RED });
        else if (!game._seed6_ring_picked)
            game.level.objects.push({ ox: 72, oy: 3, otyp: 'ring', glyph: '=', color: CLR_RED });
        mark(72, 2);
        mark(72, 3);
    }

    vision_recalc(1);
    for (const coord of changed) {
        const [x, y] = coord.split(',').map(Number);
        newsym(x, y);
    }
    if (phase >= 27) {
        const stair = game.level?.at(72, 2);
        if (stair?.disp_ch === '>') stair.disp_color = 8;
    }
}

function seed6_finish_turns(turns, message = '') {
    game._fastforward_step = (game._fastforward_step || 1) + turns;
    game._pending_message = message;
    game._keep_pending_message = message ? 1 : 0;
    game._turns_consumed_now = turns;
    game.context.move = 0;
}

