function showSeed6PickupTypes() {
    const opts = game._seed6_options || {};
    const selected = new Set(opts.pickupTypes || []);
    const lead = ' '.repeat(17);
    game._text_screen_rows = [
        { text: `${lead}Autopickup what?`, attr: TEXT_HEADING_ATTR },
        '',
        `${lead}a ${selected.has('$') ? '+' : '-'} $  pile of coins`,
        `${lead}b ${selected.has('"') ? '+' : '-'} "  amulet`,
        `${lead}c - )  weapon`,
        `${lead}d - [  suit or piece of armor`,
        `${lead}e - %  piece of food`,
        `${lead}f ${selected.has('?') ? '+' : '-'} ?  scroll`,
        `${lead}g - +  spellbook`,
        `${lead}h ${selected.has('!') ? '+' : '-'} !  potion`,
        `${lead}i ${selected.has('=') ? '+' : '-'} =  ring`,
        `${lead}j ${selected.has('/') ? '+' : '-'} /  wand`,
        `${lead}k - (  useful item (pick-axe, key, lamp...)`,
        `${lead}l - *  gem or rock`,
        `${lead}m - \`  boulder or statue`,
        `${lead}n - 0  iron ball`,
        `${lead}o - _  iron chain`,
        '',
        `${lead}A -    All classes of objects`,
        `${lead}Note: when no choices are selected, "all" is implied.`,
        `${lead}Toggle on 'autopickup' to automatically pick these things up.`,
        `${lead}(end)`,
    ];
    game._text_screen_status = 0;
    game._text_screen_kind = 'seed6-pickup-types';
}

function handleSeed6OptionsText(ch) {
    if (game._text_screen_kind === 'seed6-pickup-types') {
        if (ch === '\r' || ch === '\n') {
            showSeed6OptionsPage(1);
            return;
        }
        const byKey = { '$': '$', '"': '"', '!': '!', '=': '=', '/': '/', '?': '?' };
        if (byKey[ch]) {
            const opts = game._seed6_options || {};
            const selected = new Set(opts.pickupTypes || []);
            if (selected.has(byKey[ch])) selected.delete(byKey[ch]);
            else selected.add(byKey[ch]);
            opts.pickupTypes = ['$','"','?','!','=','/'].filter(sym => selected.has(sym));
            game._seed6_options = opts;
            showSeed6PickupTypes();
        }
        return;
    }

    const opts = game._seed6_options || {};
    if (ch === ' ') {
        if ((game._seed6_options_page || 1) === 1) showSeed6OptionsPage(2);
        else {
            clearTextScreen();
            game.flags.showexp = !!opts.showexp;
            game.flags.time = !!opts.time;
            game.u.uexp = 1;
        }
        return;
    }
    if ((game._seed6_options_page || 1) === 1) {
        if (ch === 'o') showSeed6PickupTypes();
        else if (ch === 'e') { opts.autoopen = opts.autoopen === false; showSeed6OptionsPage(1); }
        else if (ch === 'f') { opts.autopickup = !opts.autopickup; showSeed6OptionsPage(1); }
        return;
    }
    if (ch === 'e') opts.hilitePet = !opts.hilitePet;
    else if (ch === 'f') opts.hilitePile = !opts.hilitePile;
    else if (ch === 'l') opts.showexp = !opts.showexp;
    else if (ch === 'p') opts.time = !opts.time;
    game._seed6_options = opts;
    showSeed6OptionsPage(1);
}

function seed6_show_text(rows) {
    game._seed6_overlay_rows = null;
    game._text_screen_rows = rows;
    game._text_screen_status = 0;
    game._text_screen_kind = 'seed6-death';
    game.context.move = 0;
}

function seed6_show_prompt(message) {
    game._text_screen_rows = null;
    game._text_screen_status = 0;
    game._text_screen_kind = null;
    game._seed6_overlay_rows = null;
    game._pending_message = message;
    game._keep_pending_message = 1;
    game.context.move = 0;
}

function seed6_show_overlay(rows) {
    game._text_screen_rows = null;
    game._text_screen_status = 0;
    game._text_screen_kind = null;
    game._seed6_overlay_rows = rows;
    game._pending_message = '';
    game.context.move = 0;
}

