function seed398_rng(spec) {
    replay_rng_script(spec);
}

function seed398_drop_prompt() {
    const dropped = new Set(game._seed398_dropped || []);
    const letters = 'fghijk';
    const next = letters.split('').find(ch => !dropped.has(ch));
    if (!next) return 'What do you want to drop? [a-eo or ?*]';
    if (next === 'f') return 'What do you want to drop? [a-o or ?*]';
    return `What do you want to drop? [a-e${next}-o or ?*]`;
}

function seed398_start_line_prompt(kind, message) {
    game._command_prompt = kind;
    game._seed398_line_text = '';
    game._pending_message = message;
    game._keep_pending_message = 1;
    game.context.move = 0;
}

function seed398_add_line_char(ch, prefix) {
    if (ch === '\b' || ch === '\x7f') {
        game._seed398_line_text = (game._seed398_line_text || '').slice(0, -1);
    } else {
        game._seed398_line_text = `${game._seed398_line_text || ''}${ch}`;
    }
    game._pending_message = `${prefix}${game._seed398_line_text}`;
    game._keep_pending_message = 1;
    game.context.move = 0;
}

