function showSeed2200LookSelection(ch) {
    if (ch === 'i') {
        showSeed2200InventoryLook();
        return true;
    }
    if (ch === 'm' || ch === 'M') {
        showSeed2200List(
            ch === 'm' ? 'Monsters currently shown near <23,9>:' : 'All monsters currently shown on the map:',
            [
                ' <23,9>   @  human wizard called merlin',
                ' <20,10>  f  tame kitten',
            ],
        );
        return true;
    }
    if (ch === 'o' || ch === 'O') {
        showSeed2200List(
            ch === 'o' ? 'Objects currently shown near <23,9>:' : 'All objects currently shown on the map:',
            [
                ' <17,10>  x  a statue of a grid bug',
                ' <18,10>  (  a large box',
            ],
        );
        return true;
    }
    if (ch === 'e' || ch === 'E') {
        showSeed2200List(
            ch === 'e' ? 'Nearby seen or remembered engravings:' : 'Seen or remembered engravings on this level:',
            [
                '  <23,9>  `  remembered text: "Elbereth", obscured by @',
            ],
        );
        return true;
    }
    if (ch === 't' || ch === 'T') {
        game._pending_message = ch === 't'
            ? 'No traps seen or remembered nearby.'
            : 'No traps seen or remembered.';
        game._keep_pending_message = 1;
        game.context.move = 0;
        return true;
    }
    return false;
}

