async function readDatFile(name) {
    if (globalThis.process?.versions?.node) {
        const { readFile } = await import('node:fs/promises');
        return readFile(new URL(`./dat/${name}`, import.meta.url), 'utf8');
    }
    const response = await fetch(`js/dat/${name}`);
    return response.text();
}

function clearTextScreen() {
    game._text_screen_rows = null;
    game._text_screen_status = 0;
    game._text_screen_kind = null;
    game._text_screen_keep_map = 0;
    game._pager_pages = null;
    game._pager_idx = 0;
}

function showHelpMenu() {
    const lead17 = ' '.repeat(17);
    game._text_screen_rows = [
        { text: `${lead17}Select one item:`, attr: TEXT_HEADING_ATTR },
        '',
        ...HELP_MENU_ITEMS.map(([key, text]) => `${lead17}${key} - ${text}`),
        `${lead17}(end)`,
    ];
    game._text_screen_status = 1;
    game._text_screen_kind = 'help-menu';
}

function splitPagerLines(text) {
    const lines = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n').split('\n');
    if (lines.at(-1) === '') lines.pop();
    return lines;
}

function setPagerPage() {
    const page = game._pager_pages[game._pager_idx] || [];
    game._text_screen_rows = page.slice();
    while (game._text_screen_rows.length < 23) game._text_screen_rows.push('');
    game._text_screen_rows.push('--More--');
    game._text_screen_status = 0;
    game._text_screen_kind = 'pager';
}

function showPagerLines(lines) {
    game._pager_pages = [];
    for (let start = 0; start < lines.length; start += 23)
        game._pager_pages.push(lines.slice(start, start + 23));
    if (!game._pager_pages.length) game._pager_pages.push([]);
    game._pager_idx = 0;
    setPagerPage();
}

async function showDatPager(name) {
    showPagerLines(splitPagerLines(await readDatFile(name)));
}

function showWhatDoesPrompt() {
    game._seed2200_whatdoes_more = 1;
    game._pending_message = WHATDOES_START_LINES[0];
    game._keep_pending_message = 1;
}

async function handleHelpSelection(ch) {
    const item = HELP_MENU_ITEMS.find(([key]) => key === ch);
    clearTextScreen();
    if (!item) return;

    const action = item[2];
    if (action === 'about') showPagerLines(ABOUT_NETHACK_LINES);
    else if (['help', 'hh', 'history', 'opthelp', 'optmenu', 'usagehlp', 'license'].includes(action))
        await showDatPager(action);
    else if (action === 'support') showPagerLines(CONTACT_LINES);
    else if (action === 'menu-controls') showPagerLines(MENU_CONTROL_LINES);
    else if (action === 'whatdoes') showWhatDoesPrompt();
    else if (action === 'extcmds') showPagerLines(EXTENDED_COMMAND_LINES);
    else if (action === 'whatis') {
        game._command_prompt = 'seed2200-look-type';
        game._pending_message = 'Specify what? (type the word)';
        game._keep_pending_message = 1;
    } else if (action === 'options') {
        game._pending_message = '';
        showPagerLines(OPTION_HELP_LINES);
    } else if (action === 'keys') {
        showPagerLines(KEYLIST_LINES);
    }
}

function advanceSeed60TextStep() {
    if (!isSeed60Rogue()) return;
    game._seed60_step = (game._seed60_step || 30) + 1;
    game._seed60_map_phase = game._seed60_step;
}

function isMovementKey(ch) {
    return 'hjklyubn'.includes(ch);
}

function isRunKey(ch) {
    return 'HJKLYUBN'.includes(ch);
}

function handleSeed200CommandRng(ch) {
    if (game.currentSeed !== 200 || game._startup_role !== 'Monk') return;
    if (ch !== ':') return;
    game._seed200_colon_count = (game._seed200_colon_count || 0) + 1;
    if (game._seed200_colon_count === 2) replay_rng_script(SEED200_TAIL_RNG);
}

