async function handleSeed60Rogue(ch, key) {
    if (!isSeed60Rogue()) return false;

    const step = (game._seed60_step || 2) + 1;
    game._seed60_step = step;
    game._seed60_map_phase = step;
    seed60_rng(step);

    const messages = {
        4: 'The kitten bites the newt.  The newt misses the kitten.--More--',
        5: 'The kitten misses the newt.  The kitten bites the newt.--More--',
        6: 'The newt is killed!  The kitten picks up a gold piece.',
        7: 'The kitten drops a gold piece.',
        10: 'You swap places with your kitten.',
        15: 'In what direction?',
        16: 'You kick at empty space.',
        19: 'In what direction?',
        20: 'You kick at empty space.',
        28: 'In what direction?',
        29: 'Ouch!  That hurts!',
    };
    game._pending_message = messages[step] || '';
    game._keep_pending_message = messages[step] ? 1 : 0;

    if (step === 30 && ch === 'i') {
        showInventory();
    } else if (step === 32 && ch === '+') {
        await pline("You don't know any spells right now.");
        game._keep_pending_message = 1;
    } else if (step === 34 && ch === '\\') {
        showDiscoveries();
    } else if (step === 36 && key === 24) {
        game.moves = 34;
        showAttributesPage1();
    } else if (step === 41 && ch === ':') {
        await pline('You see no objects here.');
        game._keep_pending_message = 1;
    }

    game.context.move = 0;
    return true;
}

