function setSeed1150Phase(phase, moves, message) {
    game._seed1150_phase = phase;
    game.moves = moves;
    game._pending_message = message;
    game._keep_pending_message = message ? 1 : 0;
    game.context.move = 0;
}

function replaySeed1150Tail() {
    if (game._seed1150_tail_rng) return;
    game._seed1150_tail_rng = 1;
    replay_rng_script(SEED1150_TAIL_RNG);
}

function handleSeed1150Caveman(ch) {
    if (game.currentSeed !== 1150 || game._startup_role !== 'Caveman') return false;
    if (ch === '\x1b') {
        setSeed1150Phase(game._seed1150_phase || 38, game.moves || 24, '');
        return true;
    }

    const fireStep = game._seed1150_fire_step || 0;
    if (fireStep && ch === ' ') {
        const messages = [
            'a - a +1 club (alternate weapon; not wielded).--More--',
            'Slasher drops a food ration.--More--',
            'In what direction?',
        ];
        const phases = [35, 36, 37];
        const moves = [22, 23, 23];
        game._seed1150_fire_step = fireStep < 3 ? fireStep + 1 : 0;
        if (fireStep === 3) game._command_prompt = 'seed1150-fire-dir';
        setSeed1150Phase(phases[fireStep - 1], moves[fireStep - 1], messages[fireStep - 1]);
        return true;
    }

    if (game._command_prompt === 'seed1150-fire-dir') {
        game._command_prompt = null;
        if (ch === 'l') setSeed1150Phase(38, 24, 'You shoot 2 flint stones.');
        else setSeed1150Phase(37, 23, 'In what direction?');
        return true;
    }

    if (ch === 'f' && (game._seed1150_phase || 5) === 33) {
        game._seed1150_fire_step = 1;
        setSeed1150Phase(34, 22, 'b - a +2 sling (weapon in right hand).--More--');
        return true;
    }

    const transition = SEED1150_TRANSITIONS[game._seed1150_phase || 5]?.[ch];
    if (!transition) return false;
    replaySeed1150Tail();
    setSeed1150Phase(...transition);
    return true;
}

